VALUES
  ('social-worker-moex-08250', 'social-worker', 'social-worker-moex-098-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Doherty與Horne（2002）在傳統的「4P」基礎上，建構出公共服務行銷組合的「5P」模式，這新增的第5個P是指：', '["產品（Product）", "人們（People）", "通路（Place）", "促銷（Promotion）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "bd967293a7d9", "answer_pdf_sha1": "822b4e781d88", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08251', 'social-worker', 'social-worker-moex-098-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列那一項敘述是屬於社會行銷的概念？', '["其行銷的產品是實質物品", "其行銷產品的地點是商業的公司或店面", "其行銷的目的都是營利的", "其行銷的產品是觀念、態度與生活方式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "bd967293a7d9", "answer_pdf_sha1": "822b4e781d88", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08252', 'social-worker', 'social-worker-moex-098-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '將一個市場區分為幾個相似的消費族群，並且為組織選擇最適合的消費群以提供產品及服務的過程，我們稱為：', '["市場區隔化", "市場開發", "市場調查", "市場美化"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "bd967293a7d9", "answer_pdf_sha1": "822b4e781d88", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08253', 'social-worker', 'social-worker-moex-098-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '由彼得‧杜拉克（Peter Drucker）所倡導，主張由管理者及其部屬共同設定明確的目標，並將此目標視為獎勵、評估 與控制努力的主要基礎，以「目標」而非以「手段」或「程序」來管理部屬的管理方法稱為：', '["參與管理", "目標管理", "走動管理", "時間管理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "bd967293a7d9", "answer_pdf_sha1": "822b4e781d88", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08254', 'social-worker', 'social-worker-moex-098-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「家庭暴力施暴者再犯率」的陳述是以下那一種方案成果測量方法的呈現：', '["數量的統計", "標準化工具之測量", "功能層次量表", "服務對象之滿意度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "bd967293a7d9", "answer_pdf_sha1": "822b4e781d88", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08255', 'social-worker', 'social-worker-moex-098-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '我國「公益勸募條例」規定，勸募團體應於勸募活動期滿之翌日起多少日內，將捐贈人捐贈資料、勸募活動所得與收 支報告公告及公開徵信，並報主管機關備查？', '["10天", "20天", "30天", "40天"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "bd967293a7d9", "answer_pdf_sha1": "822b4e781d88", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08256', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者不是社會保險政策的原則？', '["財務自給自足原則", "給付假定需要原則", "資產調查原則", "強制加保原則"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08257', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依老人福利法施行細則規定家庭教育及輔導，如有正當理由，得申請原處罰之主管機關同意後延期參加。其規定為何？', '["以一次為限，最長不得逾三個月", "以一次為限，最長不得逾二個月", "以一次為限，最長不得逾一個月", "以一次為限，沒有時間限制"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08258', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '主管機關應邀集老人代表、老人福利相關學者或專家、民間相關機構、團體代表及各目的事業主管機關代表，參與整 合、諮詢、協調與推動老人權益及福利相關事宜；其中應有原住民老人代表或熟諳原住民文化之專家學者多少人？', '["至少四人", "至少三人", "至少二人", "至少一人"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08259', 'social-worker', 'social-worker-moex-098-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依法令或契約有扶養照顧義務而對老人有遺棄行為者，處新臺幣罰鍰：', '["三萬元以上十五萬元以下", "三萬元以上十萬元以下", "六萬元以上十五萬元以下", "六萬元以上十萬元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "e78cbdae444d", "answer_pdf_sha1": "53304528ff4d", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
